10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const CURSED_SURCHARGE_RATE = 0.5;
12	const PROCESSING_FEE = 5;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_BASE = 60;
16	
17	const baseForType = (type: string, count: number): number => {
18	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
19	    return COMPONENT_BLOCK_BASE;
20	  }
21	  return count * BASE_PREMIUMS[type];
22	};
23	
24	export const runScenario = (scenario: any): unknown => {
25	  const items = scenario.steps[0].items;
26	  const countsByType = new Map<string, number>();
27	  for (const item of items) {
28	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
29	  }
30	  let itemBasesSum = 0;
31	  for (const [type, count] of countsByType) {
32	    itemBasesSum += baseForType(type, count);
33	  }
34	  let itemSurcharges = 0;
35	  for (const item of items) {
36	    const itemBase = BASE_PREMIUMS[item.type];
37	    if (item.cursed) {
38	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
39	    }
40	  }
41	  const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE + itemSurcharges;
42	  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
43	  return { results: [{ premium }] };
44	};
